"""
This module contains the CheckersGame class which manages the game state.
"""

from board import Board
from move import Move
from player import Player
from game_rules import GameRules

class CheckersGame:
    def __init__(self):
        self.board = Board()
        self.player1 = Player("Player 1", "red")
        self.player2 = Player("Player 2", "black")
        self.current_player = self.player1
        self.game_over = False

    def play(self):
        while not self.game_over:
            print(self.board)
            move_input = input(f"{self.current_player.name}, enter your move (e.g., A1-B3): ")
            move = Move.from_notation(move_input)
            if move.is_valid():
                self.board.apply_move(move, self.current_player.color)
                if GameRules.check_win_conditions(self.board, self.current_player.color):
                    print(f"{self.current_player.name} wins!")
                    self.game_over = True
                elif GameRules.check_draw_condition(self.board):
                    print("Game is a draw!")
                    self.game_over = True
                else:
                    self.switch_turns()
            else:
                print("Invalid move. Try again.")

    def switch_turns(self):
        if self.current_player == self.player1:
            self.current_player = self.player2
        else:
            self.current_player = self.player1

if __name__ == "__main__":
    game = CheckersGame()
    game.play()
```

