"""
This module contains the Board class which represents the checkers board.
"""

from piece import Piece, Color

class Board:
    def __init__(self):
        self.grid = [[None for _ in range(8)] for _ in range(8)]
        self.initialize_board()

    def initialize_board(self):
        colors = [Color.RED, Color.BLACK]
        positions = [(i, j) for i in range(3) for j in range(4) if (i + j) % 2 == 1] + \
                    [(i, j) for i in range(5, 8) for j in range(4) if (i + j) % 2 == 1]
        for pos, color in zip(positions, colors * len(positions)):
            self.grid[pos[0]][pos[1]] = Piece(color)

    def apply_move(self, move, player_color):
        from_pos = move.from_position
        to_pos = move.to_position
        piece = self.grid[from_pos[0]][from_pos[1]]
        if piece and piece.color == player_color:
            self.grid[to_pos[0]][to_pos[1]] = piece.move(to_pos)
            self.grid[from_pos[0]][from_pos[1]] = None

    def __str__(self):
        board_str = "  A B C D E F G H\n"
        for i, row in enumerate(self.grid):
            board_str += f"{i + 1} |{''.join(' ' if cell is None else str(cell) for cell in row)}|\n"
        return board_str
