"""
This module contains the Move class which represents a move made by a player.
"""

class Move:
    def __init__(self, from_position, to_position):
        self.from_position = from_position
        self.to_position = to_position

    @classmethod
    def from_notation(cls, notation):
        col_map = {'A': 0, 'B': 1, 'C': 2, 'D': 3, 'E': 4, 'F': 5, 'G': 6, 'H': 7}
        from_col, from_row = col_map[notation[0]], int(notation[1]) - 1
        to_col, to_row = col_map[notation[3]], int(notation[4]) - 1
        return cls((from_row, from_col), (to_row, to_col))

    def is_valid(self):
        # Simplified validation logic
        return abs(self.from_position[0] - self.to_position[0]) == 1 and \
               abs(self.from_position[1] - self.to_position[1]) == 1
